@WebService(name = "OrderProcessingService", serviceName = "OrderProcessingService", targetNamespace = "http://orderprocessing.ecommerce.com/")
@SOAPBinding(style = SOAPBinding.Style.DOCUMENT, use = SOAPBinding.Use.LITERAL)
public class OrderProcessingService {

    @WebMethod(operationName = "processOrder")
    public OrderResponse processOrder(@WebParam(name = "orderRequest") OrderRequest orderRequest) {
        OrderResponse response = new OrderResponse();
        
        try {
            if (orderRequest == null || orderRequest.getCustomerId() == null || orderRequest.getItems() == null || orderRequest.getItems().isEmpty()) {
                response.setSuccess(false);
                response.setMessage("Invalid order request: Missing required fields");
                return response;
            }
            
            double totalPrice = calculateTotalPrice(orderRequest.getItems());
            
            String orderId = generateOrderId();
            String orderDate = new SimpleDateFormat("yyyy-MM-dd HH:mm:ss").format(new Date());
            
            boolean processed = saveOrder(orderId, orderRequest, totalPrice, orderDate);
            
            if (processed) {
                response.setSuccess(true);
                response.setOrderId(orderId);
                response.setTotalPrice(totalPrice);
                response.setOrderDate(orderDate);
                response.setMessage("Order processed successfully");
            } else {
                response.setSuccess(false);
                response.setMessage("Failed to process order");
            }
            
        } catch (Exception e) {
            response.setSuccess(false);
            response.setMessage("Error processing order: " + e.getMessage());
        }
        
        return response;
    }
    
    @WebMethod(operationName = "getOrderStatus")
    public OrderStatusResponse getOrderStatus(@WebParam(name = "orderId") String orderId) {
        OrderStatusResponse response = new OrderStatusResponse();
        
        try {
            if (orderId == null || orderId.isEmpty()) {
                response.setFound(false);
                response.setMessage("Invalid order ID");
                return response;
            }
            
            OrderInfo orderInfo = retrieveOrderInfo(orderId);
            
            if (orderInfo != null) {
                response.setFound(true);
                response.setOrderId(orderInfo.getOrderId());
                response.setStatus(orderInfo.getStatus());
                response.setTotalPrice(orderInfo.getTotalPrice());
                response.setCustomerId(orderInfo.getCustomerId());
                response.setOrderDate(orderInfo.getOrderDate());
                response.setMessage("Order found");
            } else {
                response.setFound(false);
                response.setMessage("Order not found");
            }
            
        } catch (Exception e) {
            response.setFound(false);
            response.setMessage("Error retrieving order status: " + e.getMessage());
        }
        
        return response;
    }
    
    @WebMethod(operationName = "calculateOrderTotal")
    public PriceCalculationResponse calculateOrderTotal(@WebParam(name = "items") List<OrderItem> items) {
        PriceCalculationResponse response = new PriceCalculationResponse();
        
        try {
            if (items == null || items.isEmpty()) {
                response.setSuccess(false);
                response.setMessage("No items provided");
                return response;
            }
            
            double subtotal = 0.0;
            double tax = 0.0;
            double shipping = 0.0;
            
            for (OrderItem item : items) {
                subtotal += item.getPrice() * item.getQuantity();
            }
            
            tax = subtotal * 0.08;
            shipping = calculateShipping(items);
            
            double total = subtotal + tax + shipping;
            
            response.setSuccess(true);
            response.setSubtotal(subtotal);
            response.setTax(tax);
            response.setShipping(shipping);
            response.setTotal(total);
            response.setMessage("Calculation successful");
            
        } catch (Exception e) {
            response.setSuccess(false);
            response.setMessage("Error calculating total: " + e.getMessage());
        }
        
        return response;
    }
    
    private double calculateTotalPrice(List<OrderItem> items) {
        double total = 0.0;
        for (OrderItem item : items) {
            total += item.getPrice() * item.getQuantity();
        }
        return Math.round(total * 100.0) / 100.0;
    }
    
    private double calculateShipping(List<OrderItem> items) {
        int totalQuantity = 0;
        for (OrderItem item : items) {
            totalQuantity += item.getQuantity();
        }
        return totalQuantity * 2.5;
    }
    
    private String generateOrderId() {
        return "ORD-" + UUID.randomUUID().toString().substring(0, 8).toUpperCase();
    }
    
    private boolean saveOrder(String orderId, OrderRequest orderRequest, double totalPrice, String orderDate) {
        System.out.println("Saving order: " + orderId);
        System.out.println("Customer ID: " + orderRequest.getCustomerId());
        System.out.println("Total Price: $" + totalPrice);
        System.out.println("Order Date: " + orderDate);
        System.out.println("Items: " + orderRequest.getItems().size());
        
        for (OrderItem item : orderRequest.getItems()) {
            System.out.println("  - " + item.getItemName() + " x" + item.getQuantity() + " @ $" + item.getPrice());
        }
        
        return true;
    }
    
    private OrderInfo retrieveOrderInfo(String orderId) {
        OrderInfo info = new OrderInfo();
        info.setOrderId(orderId);
        info.setStatus("Processing");
        info.setTotalPrice(150.00);
        info.setCustomerId("CUST-12345");
        info.setOrderDate(new SimpleDateFormat("yyyy-MM-dd HH:mm:ss").format(new Date()));
        return info;
    }
}

